     1→import { createClient } from "@/lib/supabase/client";
     2→import type { Guide } from "@/types";
     3→import type { MediaFile } from "@/components/create/media-upload";
     4→import type { ParsedMessage } from "@/lib/parser/claude-code";
     5→
     6→export async function fetchGuides(sort: string = "trending", search?: string): Promise<Guide[]> {
     7→  const supabase = createClient();
     8→
     9→  let query = supabase
    10→    .from("posts")
    11→    .select(`
    12→      *,
    13→      profile:profiles!posts_user_id_fkey(*),
    14→      media:post_media(*)
    15→    `)
    16→    .eq("is_hidden", false);
    17→
    18→  if (search) {
    19→    query = query.or(`title.ilike.%${search}%,description.ilike.%${search}%`);
    20→  }
    21→
    22→  switch (sort) {
    23→    case "recent":
    24→      query = query.order("created_at", { ascending: false });
    25→      break;
    26→    case "popular":
    27→      query = query.order("likes_count", { ascending: false });
    28→      break;
    29→    case "trending":
    30→    default:
    31→      query = query.order("trending_score", { ascending: false });
    32→      break;
    33→  }
    34→
    35→  const { data, error } = await query.limit(24);
    36→
    37→  if (error) {
    38→    console.error("Failed to fetch guides:", error.message);
    39→    return [];
    40→  }
    41→
    42→  return data as unknown as Guide[];
    43→}
    44→
    45→interface CreateGuideInput {
    46→  title: string;
    47→  description: string;
    48→  techs: string[];
    49→  categoryId: string | null;
    50→  mediaFiles: MediaFile[];
    51→  chatMessages: ParsedMessage[];
    52→}
    53→
    54→export async function createGuide(input: CreateGuideInput & { userId: string }): Promise<string | null> {
    55→  const supabase = createClient();
    56→  const userId = input.userId;
    57→
    58→  // 1. Insert post
    59→  const { data: post, error: postError } = await supabase
    60→    .from("posts")
    61→    .insert({
    62→      user_id: userId,
    63→      title: input.title,
    64→      description: input.description,
    65→      techs: input.techs,
    66→      category_id: input.categoryId,
    67→    })
    68→    .select("id")
    69→    .single();
    70→
    71→  if (postError || !post) {
    72→    console.error("Failed to create guide:", postError?.message);
    73→    return null;
    74→  }
    75→
    76→  // 2. Upload media files
    77→  if (input.mediaFiles.length > 0) {
    78→    const mediaRows = [];
    79→
    80→    for (let i = 0; i < input.mediaFiles.length; i++) {
    81→      const media = input.mediaFiles[i];
    82→      const ext = media.file.name.split(".").pop();
    83→      const path = `${userId}/${post.id}/${i}.${ext}`;
    84→
    85→      const { error: uploadError } = await supabase.storage
    86→        .from("post-media")
    87→        .upload(path, media.file);
    88→
    89→      if (uploadError) {
    90→        console.error("Upload error:", uploadError.message);
    91→        continue;
    92→      }
    93→
    94→      const { data: urlData } = supabase.storage
    95→        .from("post-media")
    96→        .getPublicUrl(path);
    97→
    98→      mediaRows.push({
    99→        post_id: post.id,
   100→        url: urlData.publicUrl,
   101→        type: media.type,
   102→        order: i,
   103→      });
   104→    }
   105→
   106→    if (mediaRows.length > 0) {
   107→      await supabase.from("post_media").insert(mediaRows);
   108→    }
   109→  }
   110→
   111→  // 3. Save chat messages
   112→  if (input.chatMessages.length > 0) {
   113→    const chatRows = input.chatMessages.map((msg, i) => ({
   114→      post_id: post.id,
   115→      role: msg.role,
   116→      content: msg.content,
   117→      tool_action: msg.toolAction,
   118→      file_path: msg.filePath,
   119→      order: i,
   120→    }));
   121→
   122→    // Insert in batches of 500 (Supabase limit)
   123→    for (let i = 0; i < chatRows.length; i += 500) {
   124→      const batch = chatRows.slice(i, i + 500);
   125→      const { error: chatError } = await supabase
   126→        .from("chat_messages")
   127→        .insert(batch);
   128→
   129→      if (chatError) {
   130→        console.error("Chat insert error:", chatError.message);
   131→      }
   132→    }
   133→  }
   134→
   135→  return post.id;
   136→}
   137→
   138→interface UpdateGuideInput {
   139→  title: string;
   140→  description: string;
   141→  techs: string[];
   142→  categoryId: string | null;
   143→}
   144→
   145→export async function updateGuide(guideId: string, input: UpdateGuideInput): Promise<Guide | null> {
   146→  const supabase = createClient();
   147→
   148→  const { data, error } = await supabase
   149→    .from("posts")
   150→    .update({
   151→      title: input.title,
   152→      description: input.description,
   153→      techs: input.techs,
   154→      category_id: input.categoryId,
   155→    })
   156→    .eq("id", guideId)
   157→    .select(`
   158→      *,
   159→      profile:profiles!posts_user_id_fkey(*),
   160→      category:categories!posts_category_id_fkey(*),
   161→      media:post_media(*)
   162→    `)
   163→    .single();
   164→
   165→  if (error || !data) {
   166→    console.error("Failed to update guide:", error?.message);
   167→    return null;
   168→  }
   169→
   170→  return data as unknown as Guide;
   171→}
   172→
   173→export async function deleteGuide(guideId: string): Promise<boolean> {
   174→  const supabase = createClient();
   175→
   176→  const { error } = await supabase
   177→    .from("posts")
   178→    .update({ is_hidden: true })
   179→    .eq("id", guideId);
   180→
   181→  if (error) {
   182→    console.error("Failed to delete guide:", error.message);
   183→    return false;
   184→  }
   185→
   186→  return true;
   187→}
