     1→/**
     2→ * Parser for Claude Code JSONL conversation history.
     3→ *
     4→ * Claude Code stores conversations in ~/.claude/projects/{project-path}/{uuid}.jsonl
     5→ * Each line is a JSON object with a "type" field:
     6→ *   - "user" (role: "user")     → user messages
     7→ *   - "assistant" (role: "assistant") → assistant messages with text, thinking, or tool_use
     8→ *   - "progress"               → ignored
     9→ *   - "file-history-snapshot"   → ignored
    10→ *
    11→ * Content can be a string or an array of content blocks:
    12→ *   { type: "text", text: "..." }
    13→ *   { type: "tool_use", name: "Write", input: { file_path: "...", ... } }
    14→ *   { type: "tool_result", content: "..." }
    15→ */
    16→
    17→export interface ParsedMessage {
    18→  role: "human" | "assistant";
    19→  content: string;
    20→  toolAction: string | null;
    21→  filePath: string | null;
    22→}
    23→
    24→interface RawMessage {
    25→  type: string;
    26→  role?: string;
    27→  content?: string | ContentBlock[];
    28→  message?: {
    29→    role: string;
    30→    content: string | ContentBlock[];
    31→  };
    32→}
    33→
    34→interface ContentBlock {
    35→  type: string;
    36→  text?: string;
    37→  name?: string;
    38→  input?: Record<string, unknown>;
    39→}
    40→
    41→function extractContent(content: string | ContentBlock[]): {
    42→  text: string;
    43→  toolAction: string | null;
    44→  filePath: string | null;
    45→} {
    46→  if (typeof content === "string") {
    47→    // Strip XML tags from system messages
    48→    const cleaned = content
    49→      .replace(/<[^>]+>/g, "")
    50→      .replace(/\s+/g, " ")
    51→      .trim();
    52→    return { text: cleaned, toolAction: null, filePath: null };
    53→  }
    54→
    55→  let text = "";
    56→  let toolAction: string | null = null;
    57→  let filePath: string | null = null;
    58→
    59→  for (const block of content) {
    60→    if (block.type === "text" && block.text) {
    61→      text += block.text;
    62→    } else if (block.type === "tool_use" && block.name) {
    63→      toolAction = block.name;
    64→      if (block.input) {
    65→        const fp =
    66→          (block.input.file_path as string) ||
    67→          (block.input.path as string) ||
    68→          (block.input.command as string);
    69→        if (fp) filePath = fp;
    70→      }
    71→    }
    72→    // Skip tool_result, thinking blocks
    73→  }
    74→
    75→  return { text: text.trim(), toolAction, filePath };
    76→}
    77→
    78→export function parseClaudeCodeJsonl(jsonlContent: string): ParsedMessage[] {
    79→  const lines = jsonlContent.split("\n").filter((l) => l.trim());
    80→  const messages: ParsedMessage[] = [];
    81→
    82→  for (const line of lines) {
    83→    let raw: RawMessage;
    84→    try {
    85→      raw = JSON.parse(line);
    86→    } catch {
    87→      continue;
    88→    }
    89→
    90→    // Only process user and assistant messages
    91→    if (raw.type !== "user" && raw.type !== "assistant") continue;
    92→
    93→    const msg = raw.message ?? raw;
    94→    const role = (msg.role ?? raw.type) as string;
    95→
    96→    if (role !== "user" && role !== "assistant") continue;
    97→
    98→    const content = msg.content;
    99→    if (!content) continue;
   100→
   101→    const { text, toolAction, filePath } = extractContent(
   102→      content as string | ContentBlock[]
   103→    );
   104→
   105→    // Skip empty messages, system commands, tool results
   106→    if (!text && !toolAction) continue;
   107→
   108→    // Skip system/command messages from user
   109→    if (role === "user" && text.startsWith("Caveat:")) continue;
   110→
   111→    messages.push({
   112→      role: role === "user" ? "human" : "assistant",
   113→      content: text,
   114→      toolAction,
   115→      filePath,
   116→    });
   117→  }
   118→
   119→  return messages;
   120→}
   121→
   122→/**
   123→ * Find .claude JSONL files in a directory listing.
   124→ * Users select the project root, we look for .claude/ folder inside.
   125→ */
   126→export function findClaudeCodeFiles(
   127→  files: File[]
   128→): { conversationFiles: File[]; source: "claude-code" } | null {
   129→  const jsonlFiles = files.filter(
   130→    (f) =>
   131→      f.webkitRelativePath?.includes(".claude/") &&
   132→      f.name.endsWith(".jsonl") &&
   133→      !f.webkitRelativePath.includes("/subagents/")
   134→  );
   135→
   136→  if (jsonlFiles.length === 0) return null;
   137→
   138→  // Sort by last modified (most recent first)
   139→  jsonlFiles.sort((a, b) => b.lastModified - a.lastModified);
   140→
   141→  return { conversationFiles: jsonlFiles, source: "claude-code" };
   142→}
